local function C_2()
local script = G2L["2"];
	local UIS = game:GetService("UserInputService")
	local TweenService = game:GetService("TweenService")
	local Players = game:GetService("Players")
	local GuiService = game:GetService("GuiService")
	
	local player = Players.LocalPlayer
	local playerGui = player:WaitForChild("PlayerGui")
	local thisGui = script.Parent
	
	-- Toggle UI
	UIS.InputBegan:Connect(function(input, gameProcessed)
		if gameProcessed then return end
		if input.KeyCode == Enum.KeyCode.LeftControl then
			thisGui.Enabled = not thisGui.Enabled
		end
	end)
	
	-- Prevent duplicates
	for _, gui in ipairs(playerGui:GetChildren()) do
		if gui ~= thisGui and gui.Name == thisGui.Name then
			gui:Destroy()
		end
	end
	
	local RIPPLE_COLOR = Color3.fromRGB(255, 255, 255)
	local RIPPLE_TRANSPARENCY = 0.6
	local TWEEN_TIME = 0.67
	
	local function createRipple(button, x, y)
		-- Check for UICorner to handle clipping properly
		local corner = button:FindFirstChildOfClass("UICorner")
		local parentContainer = button
	
		if corner then
			-- Create a CanvasGroup to force rounding-aware clipping
			local mask = button:FindFirstChild("RippleMask")
			if not mask then
				mask = Instance.new("CanvasGroup")
				mask.Name = "RippleMask"
				mask.BackgroundTransparency = 1
				mask.Size = UDim2.fromScale(1, 1)
				mask.ZIndex = button.ZIndex
	
				local maskCorner = corner:Clone()
				maskCorner.Parent = mask
				mask.Parent = button
			end
			parentContainer = mask
		else
			button.ClipsDescendants = true
		end
	
		local ripple = Instance.new("Frame")
		ripple.BackgroundColor3 = RIPPLE_COLOR
		ripple.BackgroundTransparency = RIPPLE_TRANSPARENCY
		ripple.AnchorPoint = Vector2.new(0.5, 0.5)
		ripple.Position = UDim2.new(0, x - button.AbsolutePosition.X, 0, y - button.AbsolutePosition.Y)
		ripple.Size = UDim2.new(0, 0, 0, 0)
		ripple.ZIndex = parentContainer.ZIndex + 1
	
		local uiCorner = Instance.new("UICorner")
		uiCorner.CornerRadius = UDim.new(1, 0)
		uiCorner.Parent = ripple
	
		ripple.Parent = parentContainer
	
		local goalSize = math.max(button.AbsoluteSize.X, button.AbsoluteSize.Y) * 1.5
		local tweenInfo = TweenInfo.new(TWEEN_TIME, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)
	
		local tween = TweenService:Create(ripple, tweenInfo, {
			Size = UDim2.new(0, goalSize, 0, goalSize),
			BackgroundTransparency = 1
		})
	
		tween:Play()
		tween.Completed:Connect(function()
			ripple:Destroy()
		end)
	end
	
	local function handleButton(button)
		if button:IsA("GuiButton") then
			button.MouseButton1Click:Connect(function()
				local mousePos = UIS:GetMouseLocation()
				local guiInset = GuiService:GetGuiInset()
				createRipple(button, mousePos.X - guiInset.X, mousePos.Y - guiInset.Y)
			end)
		end
	end
	
	for _, desc in pairs(thisGui:GetDescendants()) do
		handleButton(desc)
	end
	thisGui.DescendantAdded:Connect(handleButton)
end;
task.spawn(C_2);
-- StarterGui.f789z43hfn3i._main.dh.ds
local function C_7()
local script = G2L["7"];
	local UIS = game:GetService("UserInputService")
	local TweenService = game:GetService("TweenService")
	
	local dragHandle = script.Parent
	
	local mainFrame = script.Parent.Parent
	local tskFrame = script.Parent.Parent.Parent:WaitForChild("tsk")
	
	local dragging = false
	local dragStart
	local startPosMain
	local startPosTsk
	local dragSpeed = 0.1
	
	
	local function updateInput(input)
		local delta = input.Position - dragStart
	
		local newMainPos = UDim2.new(
			startPosMain.X.Scale,
			startPosMain.X.Offset + delta.X,
			startPosMain.Y.Scale,
			startPosMain.Y.Offset + delta.Y
		)
	
		local newTskPos = UDim2.new(
			startPosTsk.X.Scale,
			startPosTsk.X.Offset + delta.X,
			startPosTsk.Y.Scale,
			startPosTsk.Y.Offset + delta.Y
		)
	
		TweenService:Create(mainFrame, TweenInfo.new(dragSpeed), {Position = newMainPos}):Play()
		TweenService:Create(tskFrame, TweenInfo.new(dragSpeed), {Position = newTskPos}):Play()
	end
	
	
	dragHandle.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 then
	
			dragging = true
			dragStart = input.Position
	
			startPosMain = mainFrame.Position
			startPosTsk = tskFrame.Position
	
			input.Changed:Connect(function()
				if input.UserInputState == Enum.UserInputState.End then
					dragging = false
				end
			end)
		end
	end)
	
	
	UIS.InputChanged:Connect(function(input)
		if dragging and (input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch) then
			updateInput(input)
		end
	end)
	
end;
