local function C_3b()
local script = G2L["3b"];
	local TeleportService = game:GetService("TeleportService")
	local Players = game:GetService("Players")
	local LocalPlayer = Players.LocalPlayer
	local placeId = game.PlaceId
	local jobId = game.JobId
	local randomServerButton = script.Parent:WaitForChild("shbtn")
	local rejoinServerButton = script.Parent:WaitForChild("rjbtn")
	
	TeleportService.TeleportInitFailed:Connect(function()
		task.wait(5)
		pcall(function()
			loadstring(game:HttpGet("https://raw.githubusercontent.com/codexvsberserkerxylo/SBscripts/refs/heads/main/lunar"))()
		end)
	end)
	
	function queueReload()
		local queued = [[
	        task.wait(5)
	        loadstring(game:HttpGet("https://raw.githubusercontent.com/codexvsberserkerxylo/SBscripts/refs/heads/main/lunar"))()
	    ]]
		if syn and syn.queue_on_teleport then
			syn.queue_on_teleport(queued)
		elseif queue_on_teleport then
			queue_on_teleport(queued)
		elseif fluxus and fluxus.queue_on_teleport then
			fluxus.queue_on_teleport(queued)
		end
	end
	
	function joinRandomServer()
		queueReload()
	
		local HttpService = game:GetService("HttpService")
		local servers = {}
		local cursor = ""
	
		local success, response = pcall(function()
			return game:HttpGet("https://games.roblox.com/v1/games/" .. placeId .. "/servers/Public?sortOrder=Asc&limit=100")
		end)
	
		if not success then
			return
		end
	
		local data = HttpService:JSONDecode(response)
		if not data or not data.data or #data.data == 0 then
			return
		end
	
		for _, server in ipairs(data.data) do
			if server.playing < server.maxPlayers and server.id ~= jobId then
				table.insert(servers, server.id)
			end
		end
	
		if #servers == 0 then
			return
		end
	
		local randomServer = servers[math.random(1, #servers)]
		local success2, err = pcall(function()
			game:GetService("TeleportService"):TeleportToPlaceInstance(placeId, randomServer, LocalPlayer)
		end)
	
		if not success2 then
			print("h")
		else
			print("h")
		end
	end
	
	function rejoinServer()
		if jobId == "" then
			return
		end
		queueReload()
		local success, result = pcall(function()
			TeleportService:TeleportToPlaceInstance(placeId, jobId, LocalPlayer)
		end)
		if not success then
			print("h")
		end
	end
	
	local connections = {}
	table.insert(connections, randomServerButton.MouseButton1Click:Connect(joinRandomServer))
	table.insert(connections, rejoinServerButton.MouseButton1Click:Connect(rejoinServer))
	
	script.AncestryChanged:Connect(function()
		if not script.Parent then
			for _, conn in ipairs(connections) do
				conn:Disconnect()
			end
		end
	end)
end;
task.spawn(C_3b);
