	local ANIM = TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)
	local RIGHT = UDim2.new(0.506, 0, 0, 0)
	local LEFT = UDim2.new(0, 0, 0, 0)
	
