		local preset = getCurrentColor()
		local textLabel = colorButton:FindFirstChildOfClass("TextLabel")
		if textLabel then
			textLabel.Text = preset.name
			local r = tonumber(preset.hex:sub(2,3), 16) / 255
			local g = tonumber(preset.hex:sub(4,5), 16) / 255
			local b = tonumber(preset.hex:sub(6,7), 16) / 255
			textLabel.TextColor3 = Color3.new(r, g, b)
		else
			colorButton.Text = preset.name
			local r = tonumber(preset.hex:sub(2,3), 16) / 255
			local g = tonumber(preset.hex:sub(4,5), 16) / 255
			local b = tonumber(preset.hex:sub(6,7), 16) / 255
