	local function animateToggle(btn, on)
		local bar = btn:FindFirstChild("tfrm") and btn.tfrm:FindFirstChild("bar")
		if bar then
			TweenService:Create(bar, ANIM, {Position = on and RIGHT or LEFT, BackgroundColor3 = on and GREEN or RED}):Play()
		end
	end
	
	local osuSound = Instance.new("Sound")
	osuSound.SoundId = "rbxassetid://7172607676"
	osuSound.Volume = 0.8
	osuSound.Parent = player
	
	local function hookTextbox(tb)
		if tb:GetAttribute("OsuHooked") then return end
		tb:SetAttribute("OsuHooked", true)
		tb:GetPropertyChangedSignal("Text"):Connect(function()
			if not state.osu then return end
			local len = #tb.Text
			osuSound.PlaybackSpeed = 1.0 + (len * 0.015)
			osuSound:Stop()
			osuSound:Play()
		end)
	end
	
	for _, gui in ipairs(PlayerGui:GetChildren()) do
		for _, tb in ipairs(gui:GetDescendants()) do
			if tb:IsA("TextBox") then hookTextbox(tb) end
		end
	end
	
	PlayerGui.DescendantAdded:Connect(function(d)
		if d:IsA("TextBox") then hookTextbox(d) end
	end)
	
	consoleTextBox.ClearTextOnFocus = false
	consoleTextBox.MultiLine = true
