	scrollFrame.ScrollBarThickness = 6
	
	local lines = {}
	local MAX_LINES = 500
	
	local function log(text)
		table.insert(lines, text)
		if #lines > MAX_LINES then table.remove(lines, 1) end
		consoleTextBox.Text = table.concat(lines, "\n")
		local textHeight = consoleTextBox.TextBounds.Y + 12
		scrollFrame.CanvasSize = UDim2.new(0, 0, 0, textHeight)
		scrollFrame.CanvasPosition = Vector2.new(0, math.max(0, textHeight - scrollFrame.AbsoluteWindowSize.Y))
	end
	
	local function getRemoteNames()
		if GAME == "ORIGINAL" then return {"PlayerText", "UpdateMonitorText"}
		elseif GAME == "XISTER" then return {"TypingEvent"}
		elseif GAME == "THE_SB" then return {"Type"}
		elseif GAME == "CARL" then return {"CheckSpelling", "UpdateSpellingText", "ChangeCurrentText"}
		elseif GAME == "BESTPLAYER" or GAME == "ONEX" then return {"TypingEvent"}
		elseif GAME == "NUNU" then return {"SpellingBeeRemote"}
		elseif GAME == "SHIVA" then return {"NextTurn", "UpdateSignText"}
		elseif GAME == "OIIA" or GAME == "CUPS" then return {"SubmitSpelling", "TypingUpdate"}
		elseif GAME == "GALAXY" then return {"SubmitWord", "UpdateBoard"}
		elseif GAME == "SPELLING_MASTERS" then return {"SubmitAnswerEvent", "UpdateTypingEvent"}
		end
		return {"PlayerText", "UpdateMonitorText"}
	end
	
	local function valToStr(v)
		local t = typeof(v)
		if t == "string" then return '"' .. v .. '"' end
		if t == "number" or t == "boolean" then return tostring(v) end
		if t == "table" then
			local out = "{"
			local count = 0
			for k, val in pairs(v) do
				count = count + 1
				if count > 6 then break end
				out = out .. "[" .. tostring(k) .. "]=" .. valToStr(val) .. ","
			end
			return out .. "...}"
		end
		return tostring(v)
	end
	
	local function findRemote(name)
		local events = ReplicatedStorage:FindFirstChild("Events") or ReplicatedStorage:FindFirstChild("events")
		if events then
			local r = events:FindFirstChild(name)
			if r then return r end
		end
		local remotes = ReplicatedStorage:FindFirstChild("Remotes")
		if remotes then
			local r = remotes:FindFirstChild(name)
			if r then return r end
		end
		return ReplicatedStorage:FindFirstChild(name)
	end
	
	local spyActive = false
	local namecallHooked = false
	local originalNamecall = nil
	local remoteLog = {}
	
	local function HasSpecial(str)
		return (str:match("%c") or str:match("%s") or str:match("%p") or tonumber(str:sub(1,1))) ~= nil
	end
	
	local function GetPath(obj)
		local parts = {}
		local cur = obj
		local err = false
		while cur ~= game do
			if cur == nil then err = true break end
			table.insert(parts, 1, cur.Parent == game and cur.ClassName or tostring(cur))
			cur = cur.Parent
		end
		local result = 'game:GetService("' .. parts[1] .. '")'
		for i = 2, #parts do
			result = result .. (HasSpecial(parts[i]) and '["' .. parts[i] .. '"]' or "." .. parts[i])
		end
		return err and "nil" or result
	end
	
	local function GetType(v)
		local t = typeof(v)
		if t == "EnumItem" then return "Enum." .. tostring(v.EnumType) .. "." .. tostring(v.Name)
		elseif t == "Instance" then return GetPath(v)
		elseif t == "CFrame" then return "CFrame.new(" .. tostring(v) .. ")"
		elseif t == "Vector3" then return "Vector3.new(" .. tostring(v) .. ")"
		elseif t == "BrickColor" then return 'BrickColor.new("' .. tostring(v) .. '")'
		elseif t == "Color3" then return "Color3.new(" .. tostring(v) .. ")"
		elseif t == "string" then return '"' .. v .. '"'
		elseif t == "Ray" then return "Ray.new(Vector3.new(" .. tostring(v.Origin) .. "), Vector3.new(" .. tostring(v.Direction) .. "))"
		end
		return tostring(v)
	end
	
	local function Table_TS(T)
		local M = {}
		for i, v in pairs(T) do
			local I = "\n\t" .. (type(i) == "number" and "[" .. i .. "] = " or '["' .. i .. '"] = ')
			table.insert(M, I .. (type(v) == "table" and Table_TS(v) or GetType(v)))
		end
		return "\n{" .. table.concat(M, ", ") .. "\n}"
	end
	
	local function buildScript(object, method, ...)
		local src = "-- Script generated by Lunar X\n-- Lunar X developed by _n.ick\n \n"
		local args = {...}
		local argNames = {}
		for i, v in ipairs(args) do
			src = src .. "local A_" .. i .. " = " .. (type(v) == "table" and Table_TS(v) or GetType(v)) .. "\n"
			argNames[#argNames+1] = "A_" .. i
		end
		src = src .. "local Event = " .. GetPath(object) .. "\n\n"
		src = src .. "Event:" .. method .. "(" .. table.concat(argNames, ", ") .. ")"
		return src
	end
	
	local function hookNamecall()
		if namecallHooked then return end
		local meta = getrawmetatable(game)
		local orig = meta.__namecall
		originalNamecall = orig
		namecallHooked = true
	
		local mwr
		if setreadonly then mwr = function() setreadonly(meta, false) end
		elseif make_writeable then mwr = function() make_writeable(meta) end end
		if mwr then mwr() end
	
		meta.__namecall = function(object, ...)
			local method = tostring(getnamecallmethod())
			if spyActive and method:match("Server") and object.Name ~= "CharacterSoundEvent" then
				local args = {...}
				local built = buildScript(object, method == "FireServer" and "FireServer" or "InvokeServer", table.unpack(args))
				local msg = "→ [" .. object.Name .. ":" .. method .. "]"
				for _, a in ipairs(args) do msg = msg .. " " .. valToStr(a) end
				log(msg)
				table.insert(remoteLog, {name=object.Name, method=method, script=built})
			end
			return orig(object, ...)
		end
	end
	
	local function startSpy()
		if state.spy then return end
		state.spy = true
		spyActive = true
		hookNamecall()
		log("rspy started [namecall hook] for " .. GAME)
	end
	
	local function stopSpy()
		if not state.spy then return end
		state.spy = false
		spyActive = false
		log("rspy stopped")
	end
	
	local function spamStandard(text)
		local A_2 = math.random(0, 1)
		local A_3 = math.random(0, 1)
		local Event = ReplicatedStorage:FindFirstChild("MessageSentRE")
		if Event then Event:FireServer(text, A_2, A_3) end
	end
	
	local function spamColor(text)
		local preset = getCurrentColor()
		local A_1 = "<font color='" .. preset.hex .. "'>" .. text .. "</font>"
		local Event = ReplicatedStorage:FindFirstChild("SystemEvent")
		if Event then Event:FireServer(A_1) end
	end
	
	local function startGalaxyCatSpam()
		if state.galaxyCat then return end
		state.galaxyCat = true
		galaxyCatThread = task.spawn(function()
			while state.galaxyCat do
				local text = inputBox.Text
				if text and text ~= "" then
					if state.method == "standard" then spamStandard(text) task.wait(0.05)
					elseif state.method == "color" then spamColor(text) task.wait(0.1) end
				else task.wait(0.1) end
			end
		end)
	end
	
	local function stopGalaxyCatSpam()
		if not state.galaxyCat then return end
		state.galaxyCat = false
		if galaxyCatThread then task.cancel(galaxyCatThread) galaxyCatThread = nil end
	end
	
	local function sendXisterMessage()
		local text = inputBox.Text
		if not text or text == "" then log("no text to send") return end
		if state.method == "standard" then
			local Event = ReplicatedStorage:FindFirstChild("MessageSentRE")
			if Event then Event:FireServer(text, 0.9873249327483272, 0.6845349183446351) log("sent (standard): " .. text)
			else log("MessageSentRE not found") end
		elseif state.method == "color" then
			local preset = getCurrentColor()
			local Event = ReplicatedStorage:FindFirstChild("SystemEvent")
			if Event then Event:FireServer("<font color='" .. preset.hex .. "'>" .. text .. "</font>") log("sent (color/" .. preset.name .. "): " .. text)
			else log("SystemEvent not found") end
		end
	end
	
	local function toggleMethod()
		state.method = state.method == "standard" and "color" or "standard"
		log("method: " .. state.method)
		local textLabel = methodButton:FindFirstChildOfClass("TextLabel")
		if textLabel then textLabel.Text = state.method end
	end
	
	local function resolvePath(raw)
		local parts = {}
		for p in raw:match("^%s*(.-)%s*$"):gmatch("[^%.]+") do parts[#parts+1] = p end
		local cur = game
		for i, part in ipairs(parts) do
			if i == 1 and part:lower() == "game" then
			else
				local child = cur:FindFirstChild(part)
				if not child then
					local ok, svc = pcall(game.GetService, game, part)
					child = ok and svc or nil
				end
				if not child then return nil, "no child '" .. part .. "' at step " .. i end
				cur = child
			end
		end
		return cur, nil
	end
	
	local function getSource(obj)
		if decompile then
			local ok, src = pcall(decompile, obj)
			if ok and type(src) == "string" and #src > 10 then return src, nil end
		end
		if getscriptbytecode then
			local ok, bc = pcall(getscriptbytecode, obj)
			if ok and type(bc) == "string" and #bc > 0 then return bc, nil end
		end
		return nil, "no decompiler available"
	end
	
	local function parseEntries(src)
		local entries = {}
		local seen = {}
		local function add(word, id)
			if not seen[id] then seen[id] = true entries[#entries+1] = {word=word, id=id} end
		end
		for word, id in src:gmatch('"([A-Za-z][A-Za-z0-9_]*)"[,]?\n?%s*(%d%d%d%d%d+)') do add(word, id) end
		for word, id in src:gmatch('{%s*"([A-Za-z][A-Za-z0-9_]*)",%s*(%d%d%d%d%d+)') do add(word, id) end
		for word, id in src:gmatch('([A-Za-z][A-Za-z0-9_]*)%s*=%s*(%d%d%d%d%d+)') do add(word, id) end
		for id, word in src:gmatch('%[(%d%d%d%d%d+)%]%s*=%s*"([A-Za-z][A-Za-z0-9_]*)"') do add(word, id) end
		local capturedIds = {}
		for _, e in ipairs(entries) do capturedIds[e.id] = true end
		for id in src:gmatch('(%d%d%d%d%d+)') do
			if not capturedIds[id] then capturedIds[id] = true entries[#entries+1] = {word="null", id=id} end
		end
		return entries
	end
	
	local COL = 52
	
	local function formatGwl(entries, varName)
		local out = {"local " .. varName .. " = {"}
		for _, e in ipairs(entries) do
			local kPart = '\t["rbxassetid://' .. e.id .. '"]'
			local padding = string.rep(" ", math.max(1, COL - #kPart))
			out[#out+1] = kPart .. padding .. '= "' .. e.word .. '",'
		end
		out[#out+1] = "}"
		return table.concat(out, "\n")
	end
	
	local function flog(m)
		fmtStatus.Text = m
		log("[fmt] " .. m)
	end
	
	local function processOne(pathStr, idx, total, all, seenGlobal)
		flog("module " .. idx .. "/" .. total .. " → " .. pathStr)
		local obj, pathErr = resolvePath(pathStr)
		if not obj then flog("path error: " .. pathErr) return end
		if not (obj:IsA("ModuleScript") or obj:IsA("LocalScript") or obj:IsA("Script")) then
			flog("not a script: " .. obj.ClassName) return
		end
		flog("decompiling...")
		local src, deErr = getSource(obj)
		if not src then flog(deErr) return end
		flog("got " .. #src .. " bytes")
		local entries = parseEntries(src)
		flog("parsed " .. #entries .. " entries")
		if #entries == 0 then flog("no entries found") return end
		local added = 0
		for _, e in ipairs(entries) do
			if not seenGlobal[e.id] then seenGlobal[e.id] = true all[#all+1] = e added = added + 1 end
		end
		flog("added " .. added .. " | " .. (#entries - added) .. " dupes skipped")
	end
	
	local function runFormatter(paths, varName)
		local all = {}
		local seen = {}
		for idx, pathStr in ipairs(paths) do processOne(pathStr, idx, #paths, all, seen) end
		flog("total: " .. #all .. " entries | formatting...")
		local output = formatGwl(all, varName)
		local lineCount = select(2, output:gsub("\n", "")) + 1
		flog("done | " .. lineCount .. " lines | " .. #output .. " bytes")
		return output
	end
	
	local activeFmtTabs = 1
	local fmtPathBoxes = {fmtPath1, fmtPath2, fmtPath3}
	
	local function refreshFmtTabs()
		for n = 1, 3 do
			fmtPathBoxes[n].Visible = n <= activeFmtTabs
		end
		fmtTabBtn.Text = activeFmtTabs .. (activeFmtTabs == 1 and " module" or " modules")
	end
	
	fmtTabBtn.MouseButton1Click:Connect(function()
		activeFmtTabs = activeFmtTabs % 3 + 1
		refreshFmtTabs()
	end)
	
	fmtBtn.MouseButton1Click:Connect(function()
		fmtBtn.Text = "working..."
		fmtStatus.Text = "decompiling..."
		fmtStatus.TextColor3 = Color3.fromRGB(240, 195, 40)
	
		task.defer(function()
			local paths = {}
			for i = 1, activeFmtTabs do
				local t = fmtPathBoxes[i].Text:match("^%s*(.-)%s*$")
				if t and #t > 0 then paths[#paths+1] = t end
			end
	
			local varName = fmtVarName.Text:match("^%s*(.-)%s*$")
			if #varName == 0 then varName = "GwlWords" end
	
			if #paths == 0 then
				fmtStatus.Text = "enter at least one path"
				fmtStatus.TextColor3 = Color3.fromRGB(255, 70, 70)
				fmtBtn.Text = "format"
				return
			end
	
			local ok, output = pcall(runFormatter, paths, varName)
	
			if ok and output and #output > 0 then
				local cbOk = pcall(setclipboard, output)
				if cbOk then
					fmtStatus.Text = "copied to clipboard!"
					fmtStatus.TextColor3 = Color3.fromRGB(75, 255, 95)
				else
					print(output)
					fmtStatus.Text = "printed to console (no clipboard)"
					fmtStatus.TextColor3 = Color3.fromRGB(255, 180, 40)
				end
			else
				fmtStatus.Text = "error: " .. tostring(output):sub(1, 40)
				fmtStatus.TextColor3 = Color3.fromRGB(255, 55, 55)
			end
	
			fmtBtn.Text = "format"
		end)
	end)
	
	refreshFmtTabs()
	
	osuButton.MouseButton1Click:Connect(function()
		state.osu = not state.osu
		animateToggle(osuButton, state.osu)
	end)
	
	spyButton.MouseButton1Click:Connect(function()
		if state.spy then stopSpy() else startSpy() end
		animateToggle(spyButton, state.spy)
	end)
	
	galaxyCatButton.MouseButton1Click:Connect(function()
		if state.galaxyCat then stopGalaxyCatSpam() else startGalaxyCatSpam() end
		animateToggle(galaxyCatButton, state.galaxyCat)
	end)
	
	xisterButton.MouseButton1Click:Connect(function()
		sendXisterMessage()
	end)
	
	methodButton.MouseButton1Click:Connect(function()
		toggleMethod()
	end)
	
	colorButton.MouseButton1Click:Connect(function()
		currentColorIndex = currentColorIndex % #colorPresets + 1
		updateColorBtn()
		log("color: " .. getCurrentColor().name .. " (" .. getCurrentColor().hex .. ")")
	end)
	
	animateToggle(osuButton, false)
	animateToggle(spyButton, false)
	animateToggle(galaxyCatButton, false)
	updateColorBtn()
end;
