	local listLayout = container:WaitForChild("layout")
	local clearBtn = container.Parent:WaitForChild("clear", 5)
	
	local mainFrame = container.Parent.Parent
	local soundSpyBtn = mainFrame:WaitForChild("albtn")
	
	local loggedSounds = {}
	local nameCache = {}
	local GREEN = Color3.fromRGB(79, 207, 79)
	local RED = Color3.fromRGB(209, 58, 58)
	local ANIM = TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)
	local RIGHT = UDim2.new(0.506, 0, 0, 0)
	local LEFT = UDim2.new(0, 0, 0, 0)
	
	local state = {
		soundSpy = false
	}
	
	local blacklistedIds = {
		["rbxassetid://126713104371193"] = true,
		["rbxassetid://71844228777149"] = true,
