		["rbxassetid://17628228607"] = true,
		["rbxassetid://94474124409510"] = true,
	}
	
	local function animateToggle(btn, on)
		local bar = btn:FindFirstChild("tfrm") and btn.tfrm:FindFirstChild("bar")
		if bar then
			TweenService:Create(bar, ANIM, {Position = on and RIGHT or LEFT, BackgroundColor3 = on and GREEN or RED}):Play()
		end
	end
	
	listLayout:GetPropertyChangedSignal("AbsoluteContentSize"):Connect(function()
		container.CanvasSize = UDim2.new(0, 0, 0, listLayout.AbsoluteContentSize.Y + 10)
	end)
	
	local function playSoundRuntime(soundId)
		local tempSound = Instance.new("Sound")
		tempSound.SoundId = soundId
		tempSound.Volume = 4.67
		tempSound.Parent = SoundService
		tempSound:Play()
		tempSound.Ended:Connect(function()
			tempSound:Destroy()
		end)
	end
	
	local function logSound(sound)
		if not state.soundSpy then return end
	
		local id = sound.SoundId
		if id == "" or blacklistedIds[id] or loggedSounds[id] then return end
		if sound:FindFirstAncestorOfClass("CoreGui") then return end
	
		local localChar = Players.LocalPlayer.Character
		if localChar and sound:IsDescendantOf(localChar) then return end
	
		loggedSounds[id] = true
	
		local clone = template:Clone()
		clone.Name = "log_" .. id
	
		local soundBtn = clone:FindFirstChild("sound")
		local wnameLbl = clone:FindFirstChild("wname")
		local rnameLbl = clone:FindFirstChild("rname")
		local playBtn  = clone:FindFirstChild("play")
	
		if not soundBtn or not wnameLbl or not rnameLbl or not playBtn then
			clone:Destroy()
			return
		end
	
		soundBtn.Text = id
		wnameLbl.Text = sound.Name
		rnameLbl.Text = "Loading..."
		clone.Visible = true
		clone.Parent = container
	
		soundBtn.MouseButton1Click:Connect(function()
			setclipboard(id)
		end)
	
		playBtn.MouseButton1Click:Connect(function()
			playSoundRuntime(id)
		end)
	
		task.spawn(function()
			local numId = id:match("%d+")
			if numId then
				if nameCache[numId] then
					rnameLbl.Text = nameCache[numId]
				else
					local success, info = pcall(function()
						return MarketplaceService:GetProductInfo(tonumber(numId))
					end)
					if success and info then
						nameCache[numId] = info.Name
						rnameLbl.Text = "(" .. info.Name .. ")"
					else
						rnameLbl.Text = "Private / Unknown"
					end
				end
			end
		end)
	end
	
	for _, desc in ipairs(workspace:GetDescendants()) do
		if desc:IsA("Sound") then logSound(desc) end
	end
	
	game.DescendantAdded:Connect(function(desc)
		if desc:IsA("Sound") then
			task.delay(0.1, function()
				logSound(desc)
			end)
	
			desc:GetPropertyChangedSignal("SoundId"):Connect(function()
				logSound(desc)
			end)
		end
	end)
	
	soundSpyBtn.MouseButton1Click:Connect(function()
		state.soundSpy = not state.soundSpy
		animateToggle(soundSpyBtn, state.soundSpy)
	
		if state.soundSpy then
			for _, desc in ipairs(workspace:GetDescendants()) do
				if desc:IsA("Sound") then logSound(desc) end
			end
		end
	end)
	
	if clearBtn then
		clearBtn.MouseButton1Click:Connect(function()
			for _, child in ipairs(container:GetChildren()) do
				if child:IsA("Frame") and child ~= template then
					child:Destroy()
				end
			end
			table.clear(loggedSounds)
		end)
	end
	
	animateToggle(soundSpyBtn, false)
end;
