	local function consoleProgress(pct, label)
		if not rconsoleprint or not rconsoleclear then return end
		local filled = math.floor(pct / 5)
		local bar = string.rep("█", filled) .. string.rep("░", 20 - filled)
		rconsoleclear()
		if pct >= 100 then
			rconsoleprint("[████████████████████] 100% - done\n")
		else
			rconsoleprint("[" .. bar .. "] " .. pct .. "% - " .. label)
		end
	end
	
	local function notify(title, body, dur, ntype)
		dur = dur or 4
		ntype = ntype or "info"
		local card = template:Clone()
		card.Visible = true
		card.Name = "notif_" .. tostring(tick())
		local titleLbl = card:WaitForChild("titel")
		local bodyLbl = card:WaitForChild("text")
		local circle = card:WaitForChild("circle")
		titleLbl.Text = title
		bodyLbl.Text = body
		local colorMap = {
			success = Color3.fromRGB(40, 190, 80),
			info = ACCENT_COLOR,
			error = Color3.fromRGB(210, 50, 50),
			warn = Color3.fromRGB(225, 160, 25),
		}
		local imgMap = {
			success = "successimg",
			info = "infoimg",
			error = "errorimg",
			warn = "warnimg",
		}
		local col = colorMap[ntype] or colorMap.info
		local imgName = imgMap[ntype] or "infoimg"
		for _, imgChild in ipairs(circle:GetChildren()) do
			if imgChild:IsA("ImageLabel") then
				imgChild.Visible = imgChild.Name == imgName
			end
		end
		local brd = card:FindFirstChild("brd")
		if brd then brd.BackgroundColor3 = col end
		circle.BackgroundColor3 = col
		local cardH = math.max(66, bodyLbl.TextBounds.Y + 46)
		card.Size = UDim2.new(0, 240, 0, cardH)
		card.Position = UDim2.new(1, NRIGHT, 1, -(NBOTTOM + cardH))
		card.Parent = notifGui
		table.insert(activeNotifs, card)
		local function restack()
			for i, f in ipairs(activeNotifs) do
				local fH = f.Size.Y.Offset
				TweenService:Create(f, TweenInfo.new(0.25, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
					Position = UDim2.new(1, -(240 + NRIGHT), 1, -(NBOTTOM + (fH + NPAD) * i))
				}):Play()
			end
		end
		restack()
		task.delay(dur, function()
			local idx = table.find(activeNotifs, card)
			if idx then table.remove(activeNotifs, idx) end
			TweenService:Create(card, TweenInfo.new(0.2, Enum.EasingStyle.Quad), {
				Position = UDim2.new(1, NRIGHT + 240 + 10, card.Position.Y.Scale, card.Position.Y.Offset)
			}):Play()
			task.wait(0.22)
			card:Destroy()
			restack()
		end)
	end
	
