	local AVG_WORD_LEN = 13
	
	local function calcEstWpm()
		local currentSpeed = state.speed or state.normalSpeed or 1
		if state.randomSpeed then
			local min = state.minSpeed or 1
			local max = state.maxSpeed or 1
			local avg = (min + max) / 2
			if avg <= 0 then return 9999 end
			return math.floor((60000 / avg) / AVG_WORD_LEN)
		else
			if currentSpeed <= 0 then return "inf" end
			return math.floor((60000 / currentSpeed) / AVG_WORD_LEN)
		end
	end
	
	local function updateEstWpm()
		if estWpmLabel then
			estWpmLabel.Text = "est. ~" .. calcEstWpm() .. " wpm"
		end
	end
	
	local function formatSliderValue(v)
		local f = string.format("%.3f", v)
		f = f:gsub("%.?0+$", "")
		if f == "" then f = "0" end
		return f
	end
	
	local function updateWordLabel()
		wordLabel.Text = "current Word: " .. state.currentWord
	end
	
	local function updateLettersLabel(current, total)
		lettersLabel.Text = current .. "/" .. total
	end
	
	local function updateToggleBar(button, isActive)
		local bar = button:FindFirstChild("tfrm")
		if bar then
			bar = bar:FindFirstChild("bar")
			if bar then
				TweenService:Create(bar, tweenInfo, {Position = isActive and activePos or normalPos}):Play()
				TweenService:Create(bar, tweenInfo, {BackgroundColor3 = isActive and activeColor or normalColor}):Play()
			end
		end
	end
	
	local function getTypoChar(char)
		local lc = char:lower()
		if nearbyKeys[lc] then
			return nearbyKeys[lc][math.random(1, #nearbyKeys[lc])]
		end
		return char
	end
	
	local function getContWait()
		if state.randomContWait then
			local mn = state.contWaitMin
			local mx = state.contWaitMax
			if mn > mx then mn, mx = mx, mn end
			return mn + math.random() * (mx - mn)
		end
		return state.contWait + (math.random() * 0.01 - 0.005)
	end
	
	local function getTypingSpeed()
		if state.randomSpeed then
			local spd = state.minSpeed + math.random() * (state.maxSpeed - state.minSpeed)
			return math.max(spd, 0.002)
		end
		local jitter = state.normalSpeed * (math.random() * 0.1 - 0.05)
		return math.max(state.normalSpeed + jitter, 0.002)
	end
	
	local function getEnterDelay()
		if state.enterDelay <= 0 then return 0 end
		return state.enterDelay + (math.random() * 0.06 - 0.03)
	end
	
	-- FIX: Added state.autoType guards to both loops so they exit cleanly when auto-type is toggled off mid-correction.
	local function doLegitCorrection(partial, setTextFn, targetWord, typoInsertedAt)
		local extraCount = math.random(1, 3)
		local charsAdded = 0
		for e = 1, extraCount do
			if not state.autoType then break end
			local ni = typoInsertedAt + e
			local ec = (ni <= #targetWord) and getTypoChar(targetWord:sub(ni, ni)) or getTypoChar(targetWord:sub(#targetWord, #targetWord))
			partial = partial .. ec
			charsAdded = charsAdded + 1
			setTextFn(partial)
			task.wait(math.max(state.normalSpeed, 0.02))
		end
		for d = 1, charsAdded + 1 do
			if not state.autoType then break end
			task.wait(0.04 + math.random() * 0.1)
			partial = partial:sub(1, -2)
			setTextFn(partial)
		end
		return partial
	end
	
	local function doNoFixDelete(word, setTextFn)
		local typoCount = state.noFixDeleteThreshold or 4
		local indices = {}
		for i = 1, #word do indices[#indices + 1] = i end
		for i = #indices, 2, -1 do
			local j = math.random(1, i)
			indices[i], indices[j] = indices[j], indices[i]
		end
		local chosen = {}
		for i = 1, math.min(typoCount, #indices - 1) do
			chosen[indices[i]] = true
		end
		local result = ""
		for i = 1, #word do
			result = result .. (chosen[i] and getTypoChar(word:sub(i, i)) or word:sub(i, i))
		end
		for i = 1, #result do
			if not state.autoType then return result end
			setTextFn(result:sub(1, i))
			updateLettersLabel(i, #word)
			task.wait(getTypingSpeed())
		end
		task.wait(0.08 + math.random() * 0.12)
		local current = result
		for i = 1, #word do
			if not state.autoType then return word end
			if current:sub(i, i) ~= word:sub(i, i) then
				current = current:sub(1, i - 1) .. word:sub(i, i) .. current:sub(i + 1)
				setTextFn(current)
				task.wait(0.03 + math.random() * 0.06)
			end
		end
		return word
	end
	
	local function doHesitateTypo(partial, setTextFn, targetWord, i)
		task.wait(0.15 + math.random() * 0.25)
		return partial
	end
	
	local function doDoubleTypeTypo(partial, setTextFn, targetWord, i)
		local char = targetWord:sub(i, i)
		partial = partial .. char
		setTextFn(partial)
		task.wait(0.03 + math.random() * 0.05)
		partial = partial:sub(1, -2)
		setTextFn(partial)
		task.wait(0.04 + math.random() * 0.08)
		return partial
	end
	
	local function cleanWord(word)
		if word:match("^%u2705 Correct! %+%d+:") then return nil end
		word = word:gsub("^%❌ Incorrect! It was:%s*", "")
		word = word:gsub("^Spell:%s*", "")
		word = word:gsub("^Try again:%s*", "")
		return word
	end
	
	local function getDefWord()
		local ok, defText = pcall(function()
			return player.PlayerGui.ScreenGui.definitionFrame.definitionText.Text
		end)
		if ok and defText and defText ~= "" then
			for word, def in pairs(defToWord) do
				if def == defText then return word end
			end
		end
		return nil
	end
	
	local function getRemoteEvents()
		if gameType == "ORIGINAL" then
			local eventsFolder = ReplicatedStorage:FindFirstChild("Events") or ReplicatedStorage:FindFirstChild("events")
			local remoteEvent, monitorEvent
			if eventsFolder then
				remoteEvent = eventsFolder:FindFirstChild("PlayerText")
				monitorEvent = eventsFolder:FindFirstChild("UpdateMonitorText")
			end
			if not remoteEvent then remoteEvent = ReplicatedStorage:FindFirstChild("PlayerText") end
			if not monitorEvent then monitorEvent = ReplicatedStorage:FindFirstChild("UpdateMonitorText") end
			return remoteEvent, monitorEvent
	
		elseif gameType == "XISTER" then
			local excludedNames = {
				"WordCorrectionEvent","UpdateChatTags","SystemEvent","SubmitAnswer",
				"ShowSpellingGuiEvent","ShowCorrectSpelling","RoundStateEvent","RoundResult",
				"RepeatSoundEvent","PlayerWonEvent","PlayerTurnEvent","PlayAnimation",
				"AFKEvent","ChangeFontEvent","ChangeMicrophoneEvent","DescriptionEvent",
				"LucienBabaEvent","MessageSentRE","MuteAllEvent",
				"ChangeAdminWordEvent","ChangeAdminWordEventAdmin",
			}
			local function isExcluded(name)
				for _, ex in ipairs(excludedNames) do
					if name == ex then return true end
				end
				return false
			end
			for _, child in ipairs(ReplicatedStorage:GetChildren()) do
				if child:IsA("RemoteEvent") and not isExcluded(child.Name) then
					return child, nil
				end
			end
			return nil, nil
	
		elseif gameType == "THE_SB" then
			local typeEvent = ReplicatedStorage:WaitForChild("Events", 5)
			if typeEvent then typeEvent = typeEvent:FindFirstChild("Type") end
			return typeEvent, nil
	
		elseif gameType == "CARL" then
			return ReplicatedStorage:FindFirstChild("CheckSpelling"), {
				ReplicatedStorage:FindFirstChild("UpdateSpellingText"),
				ReplicatedStorage:FindFirstChild("ChangeCurrentText"),
			}
	
		elseif gameType == "BESTPLAYER" or gameType == "ONEX" then
			local eventsFolder = ReplicatedStorage:FindFirstChild("Events")
			if eventsFolder then return eventsFolder:FindFirstChild("TypingEvent"), nil end
	
		elseif gameType == "NUNU" then
			return ReplicatedStorage:FindFirstChild("SpellingBeeRemote"), nil
	
		elseif gameType == "SHIVA" then
			return ReplicatedStorage:FindFirstChild("NextTurn"), ReplicatedStorage:FindFirstChild("UpdateSignText")
	
		elseif gameType == "OIIA" then
			return ReplicatedStorage:FindFirstChild("SubmitSpelling"), ReplicatedStorage:FindFirstChild("TypingUpdate")
	
		elseif gameType == "GALAXY" then
			local remotesFolder = ReplicatedStorage:FindFirstChild("Remotes")
			if remotesFolder then
				return remotesFolder:FindFirstChild("SubmitWord"), remotesFolder:FindFirstChild("UpdateBoard")
			end
	
		elseif gameType == "SPELLING_MASTERS" then
			return ReplicatedStorage:FindFirstChild("SubmitAnswerEvent"), ReplicatedStorage:FindFirstChild("UpdateTypingEvent")
	
		elseif gameType == "CUPS" then
			return ReplicatedStorage:FindFirstChild("SubmitSpelling"), ReplicatedStorage:FindFirstChild("TypingUpdate")
		end
	
		return nil, nil
	end
	
	local function waitForTypeGui(timeout)
		if gameType == "CARL" then
			local startTime = tick()
			timeout = timeout or 5
			while tick() - startTime < timeout do
				local typeGui = playerGui:FindFirstChild("TypeGUI")
				if typeGui and typeGui.Enabled then return typeGui end
				task.wait(0.1)
			end
			return nil
		end
		local startTime = tick()
		timeout = timeout or 1
		while tick() - startTime < timeout do
			local typeGui
			if gameType == "XISTER" then typeGui = playerGui:FindFirstChild("SpellingGui")
			elseif gameType == "NUNU" then typeGui = playerGui:FindFirstChild("SpellingBeeGUI")
			elseif gameType == "SHIVA" then typeGui = playerGui:FindFirstChild("Answer")
			elseif gameType == "GALAXY" then typeGui = playerGui:FindFirstChild("MainGui")
			elseif gameType == "OIIA" then typeGui = playerGui:FindFirstChild("SpellingGui")
			elseif gameType == "CUPS" then typeGui = playerGui:FindFirstChild("SpellingGui")
			elseif gameType == "ONEX" then typeGui = playerGui:FindFirstChild("SpellingBeeGui")
			else typeGui = playerGui:FindFirstChild("Type")
			end
			if typeGui and typeGui.Enabled then return typeGui end
			task.wait()
		end
		return nil
	end
	
	local function findTextBoxInGui()
		if gameType == "XISTER" then return playerGui.SpellingGui.TextBox
		elseif gameType == "CARL" then return playerGui.Textbox.TextBox
		elseif gameType == "NUNU" then return playerGui.SpellingBeeGUI.GameFrame.Input
		elseif gameType == "SHIVA" then return playerGui.Answer.TextBox
		elseif gameType == "CUPS" then return playerGui.SpellingGui.TextBox
		elseif gameType == "OIIA" then return playerGui.SpellingGui.TextBox
		elseif gameType == "ONEX" then return playerGui.SpellingBeeGui.TextBox
		elseif gameType == "GALAXY" then
			local mainGui = playerGui:FindFirstChild("MainGui")
			if not mainGui then return nil end
			local spellingUi = mainGui:FindFirstChild("GameSpellingUi", true)
			if not spellingUi then return nil end
			return spellingUi:FindFirstChild("TextBox", true) or spellingUi:FindFirstChildWhichIsA("TextBox", true)
		else
			return playerGui.Type.TextBox
		end
	end
	
	-- FIX: FullDelete now tracks a per-call reset count to prevent a word from being
	-- deleted and restarted more than a safe number of times (avoids infinite retries).
	local function applyTypoToChar(partial, setTextFn, targetWord, i, typoCountRef, resetCountRef)
		local char = targetWord:sub(i, i)
		local method = state.typoMethod
		resetCountRef = resetCountRef or 0
	
		if method == "Hesitate" then
			partial = doHesitateTypo(partial, setTextFn, targetWord, i)
			return partial, typoCountRef, false, i + 1, resetCountRef
	
		elseif method == "DoubleType" then
			partial = doDoubleTypeTypo(partial, setTextFn, targetWord, i)
			return partial, typoCountRef, false, i + 1, resetCountRef
	
		elseif method == "Legit" then
			typoCountRef = typoCountRef + 1
			partial = partial .. getTypoChar(char)
			setTextFn(partial)
			partial = doLegitCorrection(partial, setTextFn, targetWord, i)
			setTextFn(partial)
			return partial, typoCountRef, false, i, resetCountRef
	
		elseif method == "Fix" then
			typoCountRef = typoCountRef + 1
			partial = partial .. getTypoChar(char)
			setTextFn(partial)
			task.wait(getContWait())
			partial = partial:sub(1, -2)
			setTextFn(partial)
			return partial, typoCountRef, false, i, resetCountRef
	
		elseif method == "NoFix" then
			typoCountRef = typoCountRef + 1
			partial = partial .. getTypoChar(char)
			setTextFn(partial)
			return partial, typoCountRef, false, i + 1, resetCountRef
	
		elseif method == "FullDelete" then
			typoCountRef = typoCountRef + 1
			partial = partial .. getTypoChar(char)
			setTextFn(partial)
			task.wait(getContWait())
			if typoCountRef >= state.fullDeleteThreshold then
				-- FIX: cap resets so a very unlucky typo streak can't loop forever
				if resetCountRef >= 3 then
					partial = ""
					setTextFn(partial)
					return partial, 0, true, 1, resetCountRef
				end
				local extra = math.random(1, 2)
				for e = 1, extra do
					if not state.autoType then break end
					local ni = i + e
					local ec = ni <= #targetWord and getTypoChar(targetWord:sub(ni, ni)) or getTypoChar(char)
					partial = partial .. ec
					setTextFn(partial)
					task.wait(math.random() * 0.05 + 0.02)
				end
				partial = ""
				typoCountRef = 0
				setTextFn(partial)
				task.wait(0.04)
				return partial, typoCountRef, true, 1, resetCountRef + 1
			else
				partial = partial:sub(1, -2)
				setTextFn(partial)
				return partial, typoCountRef, false, i, resetCountRef
			end
	
		elseif method == "NoFixDelete" then
			return partial, typoCountRef, false, i, resetCountRef
		end
	
		return partial, typoCountRef, false, i, resetCountRef
	end
	
	local function checkLoseAfterWords()
		if state.loseAfterWords and state.wordsTyped >= state.loseCount then
			state.autoType = false
			state.wordsTyped = 0
			updateToggleBar(atBtn, false)
		end
	end
	
	-- FIX: pcall wraps the entire remote fire so a bad remote never crashes the caller.
	local function fireEnter(remoteEvent, partialWord, word)
		local ok, err = pcall(function()
			if gameType == "ORIGINAL" then
				remoteEvent:FireServer(partialWord, workspace:GetServerTimeNow(), true)
			elseif gameType == "XISTER" or gameType == "BESTPLAYER" or gameType == "ONEX" then
				remoteEvent:FireServer(partialWord, true)
			elseif gameType == "THE_SB" then
				remoteEvent:FireServer(partialWord, true)
			elseif gameType == "CARL" then
				remoteEvent:FireServer(word)
			elseif gameType == "NUNU" then
				remoteEvent:FireServer("SubmitSpelling", partialWord, workspace:GetServerTimeNow())
			elseif gameType == "SHIVA" then
				remoteEvent:FireServer(true, workspace:GetServerTimeNow(), #partialWord)
			elseif gameType == "OIIA" or gameType == "CUPS" then
				remoteEvent:FireServer(partialWord)
			elseif gameType == "GALAXY" then
				remoteEvent:FireServer(partialWord)
			elseif gameType == "SPELLING_MASTERS" then
				remoteEvent:FireServer(partialWord)
			end
		end)
		if not ok then
			warn("[LunarX] fireEnter error:", err)
		end
	end
	
	-- FIX: entire function body wrapped in pcall so state.isTyping is ALWAYS
	-- reset on any error path, preventing a permanent deadlock.
	local function typeWordInput(word)
		if state.isTyping then return end
		state.isTyping = true
	
		local ok, err = pcall(function()
			if state.typingDelay > 0 then task.wait(state.typingDelay) end
	
			local typeGui = waitForTypeGui(gameType == "CARL" and 5 or 3)
			if not typeGui then return end
	
			local textbox = findTextBoxInGui()
			if not textbox then
				notify("Lunar X", "typeWordInput: TextBox not found for " .. tostring(gameType), 6.7, "warn")
				return
			end
	
			local remoteEvent = getRemoteEvents()
			local targetWord = word
			local partialWord = ""
			updateLettersLabel(0, #targetWord)
	
			local startIndex = 1
			if state.dieMode == "EarlyType" then
				startIndex = math.random(1, math.min(2, #targetWord))
			end
			local endIndex = #targetWord
			if state.dieMode == "EarlyEnter" then
				endIndex = math.max(1, #targetWord - math.random(1, 2))
			end
	
			textbox.Text = ""
	
			local function setTextbox(t) textbox.Text = t end
	
			if state.typosEnabled and state.typoMethod == "NoFixDelete" then
				partialWord = doNoFixDelete(targetWord, setTextbox)
				textbox.Text = partialWord
			else
				local typoCount = 0
				local resetCount = 0
				local i = startIndex
				while i <= endIndex do
					if not state.autoType then break end
					local char = targetWord:sub(i, i)
					local shouldTypo = state.typosEnabled and math.random(1, 100) <= state.typoChance and i < endIndex
					if shouldTypo then
						local newPartial, newCount, didFullReset, newI, newReset = applyTypoToChar(partialWord, setTextbox, targetWord, i, typoCount, resetCount)
						partialWord = newPartial
						typoCount = newCount
						resetCount = newReset
						i = didFullReset and 1 or newI
						textbox.Text = partialWord
						continue
					end
					partialWord = partialWord .. char
					textbox.Text = partialWord
					updateLettersLabel(#partialWord, #targetWord)
					if i < endIndex then task.wait(getTypingSpeed()) end
					i = i + 1
				end
			end
	
			local ed = getEnterDelay()
			if ed > 0 then task.wait(ed) end
	
			if state.autoEnter and remoteEvent then
				fireEnter(remoteEvent, partialWord, word)
				state.wordsTyped = state.wordsTyped + 1
				checkLoseAfterWords()
			end
	
			if gameType == "NUNU" then task.wait(1.5) end
		end)
	
		-- FIX: always release the lock, even on error
		state.isTyping = false
		if not ok then
			warn("[LunarX] typeWordInput error:", err)
		end
	end
	
	-- FIX: same pcall treatment for typeWordRemote
	local function typeWordRemote(word)
		if state.isTyping then return end
		state.isTyping = true
	
		local ok, err = pcall(function()
			if state.typingDelay > 0 then task.wait(state.typingDelay) end
	
			local typeGui = waitForTypeGui(gameType == "CARL" and 5 or 1)
			local guiRequired = gameType ~= "THE_SB"
				and gameType ~= "NUNU"
				and gameType ~= "SPELLING_MASTERS"
				and gameType ~= "CUPS"
				and gameType ~= "OIIA"
			if not typeGui and guiRequired then return end
	
			local textbox
			if gameType ~= "THE_SB" and gameType ~= "NUNU" and gameType ~= "SPELLING_MASTERS" then
				textbox = findTextBoxInGui()
			end
	
			local remoteEvent, secondaryRemote = getRemoteEvents()
			if not remoteEvent then
				warn("[LunarX] typeWordRemote: RemoteEvent not found for " .. tostring(gameType))
				return
			end
	
			local targetWord = word
			local partialWord = ""
			updateLettersLabel(0, #targetWord)
	
			local startIndex = 1
			if state.dieMode == "EarlyType" then
				startIndex = math.random(1, math.min(2, #targetWord))
			end
			local endIndex = #targetWord
			if state.dieMode == "EarlyEnter" then
				endIndex = math.max(1, #targetWord - math.random(1, 2))
			end
	
			-- FIX: pcall around each FireServer so a single bad keystroke event
			-- never crashes the whole typing loop.
			local function fireKeystroke(text)
				local fok, ferr = pcall(function()
					if gameType == "ORIGINAL" then
						remoteEvent:FireServer(text, workspace:GetServerTimeNow(), false)
						if secondaryRemote then secondaryRemote:FireServer(text) end
					elseif gameType == "XISTER" or gameType == "BESTPLAYER" or gameType == "ONEX" then
						remoteEvent:FireServer(text, false)
					elseif gameType == "THE_SB" then
						remoteEvent:FireServer(text)
					elseif gameType == "CARL" then
						if secondaryRemote then
							for _, remote in ipairs(secondaryRemote) do remote:FireServer(text) end
						end
					elseif gameType == "OIIA" then
						if secondaryRemote then secondaryRemote:FireServer(text) end
					elseif gameType == "CUPS" then
						if secondaryRemote then secondaryRemote:FireServer(text) end
					elseif gameType == "GALAXY" then
						if secondaryRemote then secondaryRemote:FireServer(text) end
					elseif gameType == "SHIVA" then
						if secondaryRemote then secondaryRemote:FireServer(text) end
					elseif gameType == "SPELLING_MASTERS" then
						if secondaryRemote then secondaryRemote:FireServer(text) end
					end
				end)
				if not fok then warn("[LunarX] fireKeystroke error:", ferr) end
			end
	
			local function setAndFire(t)
				if textbox then textbox.Text = t end
				fireKeystroke(t)
			end
	
			if state.typosEnabled and state.typoMethod == "NoFixDelete" then
				partialWord = doNoFixDelete(targetWord, setAndFire)
				setAndFire(partialWord)
			else
				local typoCount = 0
				local resetCount = 0
				local i = startIndex
				while i <= endIndex do
					if not state.autoType then break end
					local char = targetWord:sub(i, i)
					local shouldTypo = state.typosEnabled and math.random(1, 100) <= state.typoChance and i < endIndex
					if shouldTypo then
						local newPartial, newCount, didFullReset, newI, newReset = applyTypoToChar(partialWord, setAndFire, targetWord, i, typoCount, resetCount)
						partialWord = newPartial
						typoCount = newCount
						resetCount = newReset
						i = didFullReset and 1 or newI
						setAndFire(partialWord)
						continue
					end
					partialWord = partialWord .. char
					updateLettersLabel(#partialWord, #targetWord)
					setAndFire(partialWord)
					if i < endIndex then task.wait(getTypingSpeed()) end
					i = i + 1
				end
			end
	
			local ed = getEnterDelay()
			if ed > 0 then task.wait(ed) end
	
			if state.autoEnter then
				fireEnter(remoteEvent, partialWord, word)
				state.wordsTyped = state.wordsTyped + 1
				checkLoseAfterWords()
			end
	
			if gameType == "NUNU" then task.wait(1.5) end
		end)
	
		state.isTyping = false
		if not ok then
			warn("[LunarX] typeWordRemote error:", err)
		end
	end
	
	local manualTypingConnection
	
	-- FIX: The root cause of the game freeze. All task.wait() calls that previously
	-- ran directly inside the InputBegan callback are now wrapped in task.spawn().
	-- Yielding inside an InputBegan connection blocks Roblox's input processing
	-- thread, which is what caused the visible game freeze every time a typo fired.
	local function startManualTyping()
		local word = state.currentWord
		if not word or word == "" or word == "Waiting..." then
			notify("Lunar X", "No word detected yet", 3, "warn")
			return
		end
		state.manualWord = word
		state.manualIndex = 1
	
		local textbox = findTextBoxInGui()
		if textbox then textbox.Text = "" end
	
		local remoteEvent, secondaryRemote = getRemoteEvents()
	
		local function fireKeystroke(text)
			if not remoteEvent then return end
			local ok, err = pcall(function()
				if gameType == "ORIGINAL" then
					remoteEvent:FireServer(text, workspace:GetServerTimeNow(), false)
					if secondaryRemote then secondaryRemote:FireServer(text) end
				elseif gameType == "XISTER" or gameType == "BESTPLAYER" or gameType == "ONEX" then
					remoteEvent:FireServer(text, false)
				elseif gameType == "THE_SB" then
					remoteEvent:FireServer(text)
				elseif gameType == "CARL" then
					if secondaryRemote then
						for _, remote in ipairs(secondaryRemote) do remote:FireServer(text) end
					end
				elseif gameType == "OIIA" or gameType == "CUPS" then
					if secondaryRemote then secondaryRemote:FireServer(text) end
				elseif gameType == "GALAXY" then
					if secondaryRemote then secondaryRemote:FireServer(text) end
				elseif gameType == "SHIVA" then
					if secondaryRemote then secondaryRemote:FireServer(text) end
				elseif gameType == "SPELLING_MASTERS" then
					if secondaryRemote then secondaryRemote:FireServer(text) end
				end
			end)
			if not ok then warn("[LunarX] manual fireKeystroke error:", err) end
			if textbox then textbox.Text = text end
		end
	
		local currentPartial = ""
	
		if manualTypingConnection then
			manualTypingConnection:Disconnect()
			manualTypingConnection = nil
		end
	
		state.manualTypingEnabled = true
	
		manualTypingConnection = game:GetService("UserInputService").InputBegan:Connect(function(input, gameProcessed)
			if not state.manualTypingEnabled then
				if manualTypingConnection then
					manualTypingConnection:Disconnect()
					manualTypingConnection = nil
				end
				return
			end
			if input.UserInputType ~= Enum.UserInputType.Keyboard then return end
			local keyName = input.KeyCode.Name
			if not keyName:match("^%a$") and not keyName:match("^%d$") then return end
	
			-- FIX: Spawn all async work so the InputBegan thread is NEVER yielded.
			-- Previously every task.wait() inside here blocked Roblox's input thread
			-- causing the game to freeze until all the waits finished.
			task.spawn(function()
				local wordNow = state.manualWord
				if state.manualIndex > #wordNow then return end
	
				local shouldTypo = state.typosEnabled
					and math.random(1, 100) <= state.typoChance
					and state.manualIndex < #wordNow
				local charToType
	
				if shouldTypo then
					local method = state.typoMethod
					if method == "Legit" or method == "Fix" then
						charToType = getTypoChar(wordNow:sub(state.manualIndex, state.manualIndex))
						currentPartial = currentPartial .. charToType
						fireKeystroke(currentPartial)
						task.wait(getContWait())
						if method == "Legit" then
							local extraCount = math.random(1, 2)
							for e = 1, extraCount do
								if not state.manualTypingEnabled then break end
								local ni = state.manualIndex + e
								local ec = (ni <= #wordNow) and getTypoChar(wordNow:sub(ni, ni)) or getTypoChar(charToType)
								currentPartial = currentPartial .. ec
								fireKeystroke(currentPartial)
								task.wait(0.03)
							end
							for d = 1, extraCount + 1 do
								if not state.manualTypingEnabled then break end
								task.wait(0.05)
								currentPartial = currentPartial:sub(1, -2)
								fireKeystroke(currentPartial)
							end
						else
							currentPartial = currentPartial:sub(1, -2)
							fireKeystroke(currentPartial)
						end
						return
					elseif method == "NoFix" then
						charToType = getTypoChar(wordNow:sub(state.manualIndex, state.manualIndex))
						currentPartial = currentPartial .. charToType
						fireKeystroke(currentPartial)
						state.manualIndex = state.manualIndex + 1
						updateLettersLabel(state.manualIndex - 1, #wordNow)
						return
					elseif method == "FullDelete" then
						charToType = getTypoChar(wordNow:sub(state.manualIndex, state.manualIndex))
						currentPartial = currentPartial .. charToType
						fireKeystroke(currentPartial)
						task.wait(getContWait())
						currentPartial = ""
						state.manualIndex = 1
						fireKeystroke(currentPartial)
						updateLettersLabel(0, #wordNow)
						return
					elseif method == "Hesitate" then
						task.wait(0.15 + math.random() * 0.25)
					elseif method == "DoubleType" then
						charToType = wordNow:sub(state.manualIndex, state.manualIndex)
						currentPartial = currentPartial .. charToType
						fireKeystroke(currentPartial)
						task.wait(0.04)
						currentPartial = currentPartial:sub(1, -2)
						fireKeystroke(currentPartial)
						task.wait(0.05)
					end
				end
	
				charToType = wordNow:sub(state.manualIndex, state.manualIndex)
				currentPartial = currentPartial .. charToType
				fireKeystroke(currentPartial)
				updateLettersLabel(state.manualIndex, #wordNow)
				state.manualIndex = state.manualIndex + 1
	
				if state.manualIndex > #wordNow then
					if state.autoEnter then
						task.wait(getEnterDelay())
						if remoteEvent then
							fireEnter(remoteEvent, currentPartial, wordNow)
							state.wordsTyped = state.wordsTyped + 1
							checkLoseAfterWords()
						end
					end
					if manualTypingConnection then
						manualTypingConnection:Disconnect()
						manualTypingConnection = nil
					end
					state.manualTypingEnabled = false
					updateToggleBar(manualBtn, false)
				end
			end)
		end)
	end
	
	local function onWordDetected(word)
		word = cleanWord(word)
		if not word or word == "" then return end
		state.currentWord = word
		updateWordLabel()
		updateLettersLabel(0, #word)
		if state.manualTypingEnabled then
			state.manualWord = word
			state.manualIndex = 1
			startManualTyping()
			return
		end
		if state.autoType then
			task.spawn(function()
				if state.mode == "Input" then
					typeWordInput(word)
				else
					typeWordRemote(word)
				end
			end)
		end
	end
	
	local function onSoundPlayed(sound)
		local soundId = sound.SoundId
		if wordlist[soundId] then
			onWordDetected(wordlist[soundId])
		end
	end
	
	if Players.LocalPlayer.Character then
		Players.LocalPlayer.Character:WaitForChild("Humanoid").Died:Connect(function()
			state.wordsTyped = 0
		end)
	end
	Players.LocalPlayer.CharacterAdded:Connect(function(char)
		char:WaitForChild("Humanoid").Died:Connect(function()
			state.wordsTyped = 0
		end)
	end)
	
	if gameType == "ORIGINAL" or gameType == "XISTER" or gameType == "SHIVA" or gameType == "OIIA" then
		workspace.DescendantAdded:Connect(function(descendant)
			if descendant:IsA("Sound") then
				descendant:GetPropertyChangedSignal("Playing"):Connect(function()
					if descendant.Playing then onSoundPlayed(descendant) end
				end)
				if descendant.Playing then onSoundPlayed(descendant) end
			end
		end)
		for _, descendant in ipairs(workspace:GetDescendants()) do
			if descendant:IsA("Sound") and descendant.Playing then
				onSoundPlayed(descendant)
			end
		end
	
	elseif gameType == "THE_SB" then
		local gameInfo = ReplicatedStorage:FindFirstChild("GameInfo")
		if gameInfo then
			local wordValue = gameInfo:FindFirstChild("CurrentWord")
			if wordValue then
				wordValue:GetPropertyChangedSignal("Value"):Connect(function()
					if wordValue.Value ~= "" then onWordDetected(wordValue.Value) end
				end)
				if wordValue.Value ~= "" then onWordDetected(wordValue.Value) end
			end
		end
	
	elseif gameType == "CUPS" then
		workspace.DescendantAdded:Connect(function(descendant)
			if descendant:IsA("Sound") then
				descendant:GetPropertyChangedSignal("Playing"):Connect(function()
					if descendant.Playing then onSoundPlayed(descendant) end
				end)
				if descendant.Playing then onSoundPlayed(descendant) end
			end
		end)
		for _, descendant in ipairs(workspace:GetDescendants()) do
			if descendant:IsA("Sound") and descendant.Playing then
				onSoundPlayed(descendant)
			end
		end
	
	elseif gameType == "CARL" then
		local wordValue = ReplicatedStorage:FindFirstChild("WordValue")
		if wordValue then
			wordValue:GetPropertyChangedSignal("Value"):Connect(function()
