			end)
			if wordValue.Value ~= "" then onWordDetected(wordValue.Value) end
		end
	
	elseif gameType == "NUNU" then
		local spellingGui = playerGui:WaitForChild("SpellingBeeGUI", 10)
		if spellingGui then
			local gameFrame = spellingGui:FindFirstChild("GameFrame")
			if gameFrame then
				local wordLbl2 = gameFrame:FindFirstChild("Word")
				if wordLbl2 then
					wordLbl2:GetPropertyChangedSignal("Text"):Connect(function()
						local cleaned = cleanWord(wordLbl2.Text)
						if cleaned and cleaned ~= "" then onWordDetected(cleaned) end
					end)
					local cleaned = cleanWord(wordLbl2.Text)
					if cleaned and cleaned ~= "" then onWordDetected(cleaned) end
				end
			end
		end
	
	elseif gameType == "ONEX" then
		local wordsFolder = workspace:WaitForChild("Sounds", 5)
		if wordsFolder then
			wordsFolder = wordsFolder:FindFirstChild("Words")
			if wordsFolder then
				for _, sound in ipairs(wordsFolder:GetChildren()) do
					if sound:IsA("Sound") then
						sound:GetPropertyChangedSignal("Playing"):Connect(function()
							if sound.Playing then onWordDetected(sound.Name) end
