		if currentWordVal then
			currentWordVal:GetPropertyChangedSignal("Value"):Connect(function()
				if currentWordVal.Value ~= "" then onWordDetected(currentWordVal.Value) end
			end)
			if currentWordVal.Value ~= "" then onWordDetected(currentWordVal.Value) end
		else
