				if descendant:IsA("Sound") and descendant.Playing then
					if #wordlist > 0 then onWordDetected(wordlist[math.random(1, #wordlist)]) end
				end
			end)
		end
	
	elseif gameType == "SPELLING_MASTERS" then
		local wordValue = ReplicatedStorage:WaitForChild("CurrentWord", 10)
		if wordValue then
			wordValue:GetPropertyChangedSignal("Value"):Connect(function()
				if wordValue.Value ~= "" then onWordDetected(wordValue.Value) end
			end)
			if wordValue.Value ~= "" then onWordDetected(wordValue.Value) end
		end
	
	elseif gameType == "HUNDRED_PLAYER" then
		local VIM = game:GetService("VirtualInputManager")
		local lastDef = ""
		local lastReplayWord = ""
		local lastTextboxClearedAt = 0
	
		task.spawn(function()
			while true do
				if state.defMode then
					local mapped = getDefWord()
					if mapped and mapped ~= lastDef then
						lastDef = mapped
						if not state.autoType then
							state.currentWord = mapped
							updateWordLabel()
							updateLettersLabel(0, #mapped)
						end
					end
				end
	
				if state.autoType then
					local ok, textbox = pcall(function()
						return playerGui.ScreenGui.typeFrame.typeBox
					end)
					if ok and textbox and textbox.Parent.Visible then
						local word = nil
						if state.defMode then
							if lastDef ~= "" then word = lastDef end
						else
							local w = ReplicatedStorage.replayWord.Value
							if w ~= "" then
								local boxClear = (textbox.Text == "" and tick() - lastTextboxClearedAt < 0.5)
								if w ~= lastReplayWord or boxClear then
									lastReplayWord = w
									word = w
								end
							end
							if textbox.Text == "" then
								lastTextboxClearedAt = tick()
							end
						end
	
						if word then
							state.currentWord = word
							updateWordLabel()
							updateLettersLabel(0, #word)
	
							if state.typingDelay > 0 then task.wait(state.typingDelay) end
	
							task.wait(0.02)
							textbox.Text = ""
	
							local function setTB(t) textbox.Text = t end
	
							if state.typosEnabled and state.typoMethod == "NoFixDelete" then
								doNoFixDelete(word, setTB)
							else
								local baseWait = getTypingSpeed()
								if baseWait <= 0 then
									textbox.Text = word
									updateLettersLabel(#word, #word)
								else
									local typoCount = 0
									local resetCount = 0
									local i = 1
									while i <= #word do
										if not state.autoType then break end
										if not textbox.Visible then break end
										local char = word:sub(i, i)
										local shouldTypo = state.typosEnabled and math.random(1, 100) <= state.typoChance and i < #word
										if shouldTypo then
											local newPartial, newCount, didFullReset, newI, newReset = applyTypoToChar(textbox.Text, setTB, word, i, typoCount, resetCount)
											textbox.Text = newPartial
											typoCount = newCount
											resetCount = newReset
											i = didFullReset and 1 or newI
											continue
										end
										textbox.Text = textbox.Text .. char
										updateLettersLabel(i, #word)
										task.wait(getTypingSpeed())
										i = i + 1
									end
								end
							end
	
							local ed = getEnterDelay()
							if ed > 0 then task.wait(ed) end
	
							if state.autoEnter and textbox.Visible then
								textbox:CaptureFocus()
								task.wait(0.03)
								VIM:SendKeyEvent(true, Enum.KeyCode.Return, false, game)
								task.wait(0.03)
								VIM:SendKeyEvent(false, Enum.KeyCode.Return, false, game)
								state.wordsTyped = state.wordsTyped + 1
								checkLoseAfterWords()
							end
						end
					end
				end
				task.wait(0.1)
			end
		end)
	end
	
	local scriptUrl = "https://raw.githubusercontent.com/codexvsberserkerxylo/SBscripts/refs/heads/main/lunarX"
	
	local function queueReload()
		local queued = [[
