-- StarterGui.f789z43hfn3i._main._frms.efrm._scr.el.emotes
local function C_106()
local script = G2L["106"];
	local UIS = game:GetService("UserInputService")
	local TweenService = game:GetService("TweenService")
	local Players = game:GetService("Players")
	local player = Players.LocalPlayer
	local character = player.Character or player.CharacterAdded:Wait()
	local humanoid = character:WaitForChild("Humanoid")
	local animator = humanoid:WaitForChild("Animator")
	local GREEN = Color3.fromRGB(79, 207, 79)
	local RED = Color3.fromRGB(209, 58, 58)
	local ANIM  = TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)
	local RIGHT = UDim2.new(0.506, 0, 0, 0)
	local LEFT  = UDim2.new(0, 0, 0, 0)
	
	local EMOTES = {
		{ btn = script.Parent:WaitForChild("floss"),       id = "rbxassetid://94114907962580", speed = 1.4 },
		{ btn = script.Parent:WaitForChild("robot"),       id = "rbxassetid://83036970706937", speed = 1.0 },
		{ btn = script.Parent:WaitForChild("shimmy"),      id = "rbxassetid://89962140794128", speed = 1.0 },
		{ btn = script.Parent:WaitForChild("breakdance"),  id = "rbxassetid://99985453629217", speed = 1.0, moveThreshold = 7.0 },
		{ btn = script.Parent:WaitForChild("taketheL"),    id = "rbxassetid://91607646939136", speed = 1.0 },
		{ btn = script.Parent:WaitForChild("griddy"),      id = "rbxassetid://77563857457394", speed = 1.0 },
		{ btn = script.Parent:WaitForChild("bunny"),  id = "rbxassetid://85617080071654", speed = 1.0, moveThreshold = 7.0 },
	}
	
	local currentTrack = nil
	local activeEmote  = nil
	local humanoidConns = {}
	
	local function animateToggle(button, on)
		local bar = button:FindFirstChild("tfrm") and button.tfrm:FindFirstChild("bar")
		if bar then
			TweenService:Create(bar, ANIM, {
				Position         = on and RIGHT or LEFT,
				BackgroundColor3 = on and GREEN or RED,
			}):Play()
		end
	end
	
	local function initToggle(button)
		local bar = button:FindFirstChild("tfrm") and button.tfrm:FindFirstChild("bar")
		if bar then
			bar.Position = LEFT
			bar.BackgroundColor3 = RED
		end
	end
	
	local function stopAnim()
		if currentTrack then
			if currentTrack.IsPlaying then currentTrack:Stop() end
			currentTrack:Destroy()
			currentTrack = nil
		end
		if activeEmote then
			animateToggle(activeEmote.btn, false)
			activeEmote = nil
		end
	end
	
	local function playAnim(emote)
		stopAnim()
		local animation = Instance.new("Animation")
		animation.AnimationId = emote.id
		currentTrack = animator:LoadAnimation(animation)
		currentTrack.Looped = true
		currentTrack:Play()
		currentTrack:AdjustSpeed(emote.speed or 1.0)
		activeEmote = emote
		animateToggle(emote.btn, true)
		currentTrack.Stopped:Connect(function()
			if activeEmote == emote then stopAnim() end
		end)
	end
	
	local function connectHumanoidEvents()
		for _, c in ipairs(humanoidConns) do c:Disconnect() end
		humanoidConns = {}
	
		table.insert(humanoidConns, humanoid.Running:Connect(function(speed)
			if activeEmote and speed > (activeEmote.moveThreshold or 0.5) then stopAnim() end
		end))
	
		table.insert(humanoidConns, humanoid.StateChanged:Connect(function(_, newState)
			if activeEmote and (
				newState == Enum.HumanoidStateType.Jumping or
					newState == Enum.HumanoidStateType.FallingDown
				) then stopAnim() end
		end))
	end
	
	for _, emote in ipairs(EMOTES) do
		emote.btn.MouseButton1Click:Connect(function()
			if activeEmote == emote then stopAnim() else playAnim(emote) end
		end)
		initToggle(emote.btn)
	end
	
	connectHumanoidEvents()
	
	UIS.InputBegan:Connect(function(input, gameProcessed)
		if not gameProcessed and input.KeyCode == Enum.KeyCode.N and activeEmote then stopAnim() end
	end)
	
	player.CharacterAdded:Connect(function(newChar)
		character = newChar
		humanoid  = newChar:WaitForChild("Humanoid")
		animator  = humanoid:WaitForChild("Animator")
		currentTrack = nil
		if activeEmote then
			animateToggle(activeEmote.btn, false)
			activeEmote = nil
		end
		connectHumanoidEvents()
	end)
end;
task.spawn(C_106);
