local function C_138()
local script = G2L["138"];
	local Players = game:GetService("Players")
	local TweenService = game:GetService("TweenService")
	
	local button = script.Parent
	local playerGui = Players.LocalPlayer:WaitForChild("PlayerGui")
	
	local miniFolder = playerGui:WaitForChild("f789z43hfn3i")
	local mini = miniFolder:WaitForChild("_main")
	
	local minimized = false
	local sizeNormal = UDim2.new(0.34, 0, 0.453, 0)
	local sizeMin = UDim2.new(0.34, 0, 0.032, 0)
	local tweenInfo = TweenInfo.new(0.5, Enum.EasingStyle.Circular, Enum.EasingDirection.InOut)
	local isTweening = false
	
	local function setChildrenVisible(frame, visible)
		for _, child in ipairs(frame:GetChildren()) do
			if child:IsA("GuiObject") then
				if child.Name == "dh" then
					child.Visible = true
				else
					child.Visible = visible
				end
			end
		end
	end
	
	button.Active = true
	button.AutoButtonColor = true
	
	local function toggle()
		if isTweening then return end
		isTweening = true
		if not minimized then
			local t = TweenService:Create(mini, tweenInfo, {Size = sizeMin})
			t:Play()
			setChildrenVisible(mini, false)
			t.Completed:Connect(function()
				minimized = true
				isTweening = false
			end)
		else
			local t2 = TweenService:Create(mini, tweenInfo, {Size = sizeNormal})
			t2:Play()
			t2.Completed:Connect(function()
				setChildrenVisible(mini, true)
				minimized = false
				isTweening = false
			end)
		end
	end
	
	button.MouseButton1Click:Connect(toggle)
	button.Activated:Connect(toggle)
end;
